// Note: Procedural Gregorian chant and cave drips synthesis. 
//       Adapted for Desktop GLSL Audio.
// =========================================================================
// =========================================================================

#define TAU 6.28318530718
#define SR 44100.0

float hash1(float n) { return fract(sin(n) * 43758.5453123); }
float hash11(float p) { return fract(sin(p) * 43758.5453123); }

float noise1(float t) {
    float i = floor(t);
    float f = fract(t);
    float a = hash1(i);
    float b = hash1(i + 1.0);
    float u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u) * 2.0 - 1.0;
}

float softclip(float x) {
    return x / (1.0 + abs(x));
}

vec2 panEqualPower(float x, float pan) {
    pan = clamp(pan, -1.0, 1.0);
    float p = 0.5 + 0.5 * pan;
    float ang = 0.5 * TAU * p * 0.5;
    return x * vec2(cos(ang), sin(ang));
}

float panWander(float t, float rateHz, float slew, float seed) {
    float cellDur = 1.0 / max(rateHz, 1e-4);
    float id = floor((t + seed) / cellDur);
    float tt = fract((t + seed) / cellDur);
    float a = hash11(id * 13.13 + seed * 17.7) * 2.0 - 1.0;
    float b = hash11((id + 1.0) * 13.13 + seed * 17.7) * 2.0 - 1.0;
    float u = smoothstep(0.0, max(slew / cellDur, 1e-4), tt);
    return mix(a, b, u);
}

float semitoneRatio(float st) { return exp2(st / 12.0); }

float modeSemitone(int degree, bool phrygian) {
    degree = degree % 7;
    if (!phrygian) {
        if (degree == 0) return 0.0;
        if (degree == 1) return 2.0;
        if (degree == 2) return 3.0;
        if (degree == 3) return 5.0;
        if (degree == 4) return 7.0;
        if (degree == 5) return 9.0;
        return 10.0;
    } else {
        if (degree == 0) return 0.0;
        if (degree == 1) return 1.0;
        if (degree == 2) return 3.0;
        if (degree == 3) return 5.0;
        if (degree == 4) return 7.0;
        if (degree == 5) return 8.0;
        return 10.0;
    }
}

float modalDegreeTarget(float barCellId) {
    float a = hash11(barCellId * 12.7 + 1.3) * 6.0;
    float b = hash11((barCellId + 1.0) * 12.7 + 1.3) * 6.0;
    float da = floor(a + 0.5);
    float db = da + floor((hash11(barCellId * 7.9 + 9.1) * 3.0) - 1.0 + 0.5);
    return mod(da, 7.0);
}

float modalRatio(float t, float bpm, float barsPerStep, float phrygianMix) {
    float beat = 60.0 / max(bpm, 1e-3);
    float bar = beat * 4.0; 
    float stepDur = bar * max(barsPerStep, 1.0);
    float id = floor(t / stepDur);
    float ft = fract(t / stepDur);

    float degA = floor(hash11(id * 12.7 + 1.3) * 7.0);
    float step = floor(hash11(id * 7.9 + 9.1) * 3.0) - 1.0;
    float degB = mod(degA + step + 7.0, 7.0);

    float xf = smoothstep(0.0, 0.20, ft);
    float deg = mix(degA, degB, xf);

    int d0 = int(floor(deg));
    int d1 = int(mod(float(d0 + 1), 7.0));
    float u = fract(deg);

    float stD0 = modeSemitone(d0, false);
    float stD1 = modeSemitone(d1, false);
    float stP0 = modeSemitone(d0, true);
    float stP1 = modeSemitone(d1, true);

    float st0 = mix(stD0, stP0, clamp(phrygianMix, 0.0, 1.0));
    float st1 = mix(stD1, stP1, clamp(phrygianMix, 0.0, 1.0));

    float st = mix(st0, st1, u);
    return semitoneRatio(st);
}

float chantSource(float t, float f0, float tilt, float seed) {
    float ph = seed * 12.3;
    float p = TAU * f0 * t + ph;

    float s = 0.0;
    s += 1.00 * sin(1.0 * p);
    s += 0.55 * sin(2.0 * p);
    s += 0.32 * sin(3.0 * p);
    s += 0.18 * sin(4.0 * p);
    s += 0.10 * sin(5.0 * p);

    float hi = 0.0;
    hi += 0.06 * sin(6.0 * p);
    hi += 0.04 * sin(7.0 * p);
    hi += 0.03 * sin(8.0 * p);

    return s + hi * clamp(tilt, 0.0, 1.0);
}

vec3 vowel_AH() { return vec3(800.0, 1150.0, 2900.0); }
vec3 vowel_OH() { return vec3(450.0, 800.0, 2830.0); }
vec3 vowel_OO() { return vec3(325.0, 700.0, 2530.0); }

vec3 gain_AH() { return vec3(1.00, 0.55, 0.18); }
vec3 gain_OH() { return vec3(1.00, 0.52, 0.16); }
vec3 gain_OO() { return vec3(1.00, 0.45, 0.12); }

void getVowelDark(float t, out vec3 F, out vec3 G) {
    float m = fract(0.006 * t);
    float ahPulse = smoothstep(0.92, 0.98, m) * (1.0 - smoothstep(0.98, 1.00, m));
    float u = m;
    float s = u * u * (3.0 - 2.0 * u);
    vec3 Fm = mix(vowel_OO(), vowel_OH(), s);
    vec3 Gm = mix(gain_OO(), gain_OH(), s);
    F = mix(Fm, vowel_AH(), ahPulse * 0.35);
    G = mix(Gm, gain_AH(), ahPulse * 0.35);
}

float formantColor(float t, float src, vec3 F, vec3 G, float seed) {
    float w = 1.0 + 0.008 * noise1(t * 0.35 + seed * 20.0);
    float r = 0.0;
    r += G.x * sin(TAU * (F.x * w) * t + seed * 1.1);
    r += G.y * sin(TAU * (F.y * w) * t + seed * 2.2);
    r += G.z * sin(TAU * (F.z * w) * t + seed * 3.3);
    return r * (0.16 + 0.10 * clamp(abs(src), 0.0, 1.0));
}

vec2 chantStereo(float t) {
    float base = 41.2;
    float bpm = 66.0;
    float barsPerStep = 8.0;
    float phryMix = 0.65;

    float modeMul = modalRatio(t, bpm, barsPerStep, phryMix);
    float baseMod = base * modeMul;

    float vib = 0.18 * sin(TAU * 0.28 * t);
    float wander = 0.22 * noise1(t * 0.05);
    float tilt = 0.18 + 0.10 * sin(TAU * 0.006 * t);

    vec3 F, G;
    getVowelDark(t, F, G);

    vec2 acc = vec2(0.0);
    float wsum = 0.0;

    for (int i = 0; i < 10; i++) {
        float fi = float(i);
        float seed = hash1(fi * 13.7 + 2.1);
        float cents = mix(-6.0, 6.0, hash1(seed * 19.3)) + 2.0 * noise1(t * 0.025 + seed * 7.0);
        float ratio = 1.0 + cents * 0.0005776;

        float pick = hash1(seed * 31.1);
        float harm = 1.0;
        if (pick > 0.90) harm = 2.0;
        else if (pick < 0.08) harm = 0.5;

        float f0 = baseMod * harm * ratio + vib + wander;
        float v2 = 0.06 * sin(TAU * (0.18 + 0.20 * seed) * t + seed * 12.0);
        f0 += v2;

        float src = chantSource(t, f0, tilt, seed);
        float col = formantColor(t, src, F, G, seed);
        float voice = (src * 0.88 + col);
        float gain = 0.11 + 0.06 * hash1(seed * 47.0);

        float staticPan = (hash1(seed * 91.7) * 2.0 - 1.0) * 0.45;
        float driftPan = panWander(t, 0.045, 0.50, seed * 10.0) * 0.12;
        float pan = clamp(staticPan + driftPan, -1.0, 1.0);

        acc += panEqualPower(voice * gain, pan);
        wsum += gain;
    }

    vec2 outS = acc / max(wsum, 1e-4);
    float airL = noise1(t * 4500.0 + 10.0) * 0.004;
    float airR = noise1(t * 4500.0 + 23.0) * 0.004;
    outS += vec2(airL, airR);

    return outS;
}

vec2 widenMS(float t, vec2 stereo) {
    float mid = 0.5 * (stereo.x + stereo.y);
    float side = 0.5 * (stereo.x - stereo.y);
    float d = 0.0025 + 0.0010 * sin(TAU * 0.06 * t) + 0.0006 * noise1(t * 0.10);
    d = clamp(d, 0.0010, 0.0050);

    vec2 sA = chantStereo(t + d);
    vec2 sB = chantStereo(t - d);
    float sideHaas = 0.5 * ((sA.x - sA.y) - (sB.x - sB.y));

    float width = 0.45;
    side = mix(side, sideHaas, width);
    return vec2(mid + side, mid - side);
}

vec2 dcRemoveStereo(float t, int radius) {
    vec2 mean = vec2(0.0);
    float w = 0.0;
    for (int k = -24; k <= 24; k++) {
        if (abs(k) > radius) continue;
        float tk = t + float(k) / SR;
        mean += widenMS(tk, chantStereo(tk));
        w += 1.0;
    }
    mean /= max(w, 1.0);
    vec2 x = widenMS(t, chantStereo(t));
    return x - mean;
}

float envBurst(float x, float atk, float dec) {
    if (x < 0.0) return 0.0;
    float a = smoothstep(0.0, atk, x);
    float d = 1.0 / (1.0 + (x / max(dec, 1e-4)) * 6.0);
    return a * d;
}

float dripEvent(float t, float bpm, float density) {
    float beat = 60.0 / max(bpm, 1e-3);
    float cellDur = beat * 0.5;
    float id = floor(t / cellDur);
    float t0 = id * cellDur;

    float r0 = hash11(id * 17.13 + 3.1);
    float trig = step(1.0 - clamp(density, 0.0, 1.0), r0);
    float r1 = hash11(id * 11.77 + 9.4);
    float evT = t0 + (0.06 + 0.55 * r1) * cellDur;
    float x = t - evT;

    float atk = 0.0007 + 0.0012 * hash11(id * 5.3 + 1.2);
    float dec = 0.045 + 0.120 * hash11(id * 6.9 + 4.7);
    float e = envBurst(x, atk, dec) * trig;

    float tickN = noise1(t * 12000.0 + id * 0.17);
    float ringF = 900.0 + 1600.0 * hash11(id * 2.2 + 8.8);
    float ring = sin(TAU * ringF * t) * 0.30;

    float droop = exp(-max(x, 0.0) * 10.0);
    float bloopF = (120.0 + 60.0 * hash11(id * 9.1)) * (0.85 + 0.15 * droop);
    float bloop = sin(TAU * bloopF * t) * 0.35;

    float amp = 0.10 + 0.24 * hash11(id * 3.1 + 7.7);
    float s = (0.45 * tickN + 0.30 * ring + 0.55 * bloop);

    return s * e * amp;
}

float dripWithDelay(float t) {
    float bpm = 66.0;
    float density = 0.20;
    float dry = dripEvent(t, bpm, density);
    float beat = 60.0 / bpm;
    float mod = 0.006 * noise1(t * 0.55);

    float wet = 0.0;
    wet += 0.55 * dripEvent(t - (0.75 * beat + mod), bpm, density);
    wet += 0.32 * dripEvent(t - (1.25 * beat - mod), bpm, density);
    wet += 0.18 * dripEvent(t - (2.00 * beat + 1.5 * mod), bpm, density);
    wet += 0.10 * dripEvent(t - (3.25 * beat - 2.0 * mod), bpm, density);
    wet += 0.06 * dripEvent(t - (5.00 * beat + 2.5 * mod), bpm, density);

    return dry + wet;
}

float dripPan(float t, float bpm) {
    float beat = 60.0 / bpm;
    float cellDur = beat * 0.5;
    float id = floor(t / cellDur);
    float p = (hash11(id * 19.7 + 4.2) * 2.0 - 1.0) * 0.35;
    float slow = 0.15 * sin(TAU * 0.02 * t + 1.7);
    return clamp(p + slow, -1.0, 1.0);
}

// Funzione principale
vec2 mainSound(int samp, float time) {
    float t = time; 

    vec2 chant = dcRemoveStereo(t, 12);
    // VOLUME CORO: Aumentato da 0.85 a 1.2
    chant = vec2(softclip(chant.x), softclip(chant.y)) * 1.2;

    float bpm = 66.0;
    float dr = dripWithDelay(t);

    float chantLvl = clamp(0.75 * (abs(chant.x) + abs(chant.y)), 0.0, 1.0);
    float duck = 1.0 - 0.35 * chantLvl;
    dr *= duck;

    float p = dripPan(t, bpm);
    // VOLUME GOCCE: Aumentato da 0.45 a 0.7
    vec2 dripS = panEqualPower(dr, p) * 0.7;

    vec2 outS = chant + dripS;

    // VOLUME GENERALE (Master): Aumentato da 0.88 a 1.5
    outS = vec2(softclip(outS.x), softclip(outS.y)) * 1.5;

    // Aggiunto un clamp finale per evitare crash o picchi fuori scala
    return clamp(outS, -1.0, 1.0);
}
//SOUND_END

//SOUND_END

// --- PARAMETRI ---
float scale = 50.0; // Densità degli anelli (più alto = più cerchi)
vec2 center = vec2(0.5, 0.5); // Centro dei cerchi (0.5, 0.5 è il centro della texture)

// --- LOGICA ---
// 1. Calcola la distanza del pixel corrente (u, v) dal centro
float dist = distance(vec2(u, v), center);

// 2. Crea l'onda sinusoidale basata sulla distanza
// Moltiplichiamo per 'scale' per aumentare la frequenza
float val = sin(dist * scale);

// 3. Mappiamo il risultato da -1..1 a 0..1 per il mix
float t = (val + 1.0) * 0.5;

// 4. Mix finale
return mix(u_col1, u_col2, t);
